query:
-- Jogos sem nome de time (integridade)
SELECT COUNT(*) AS jogos_sem_teamAName FROM games WHERE tournamentId = 60001 AND (teamAName IS NULL OR teamAName = '');

-- Amostra de 5 jogos com nomes para confirmar dados reais
SELECT id, teamAName, scoreA, scoreB, teamBName, phase, matchDate, externalId
FROM games WHERE tournamentId = 60001 AND teamAName IS NOT NULL ORDER BY matchDate DESC LIMIT 5;

